def parse_xml(text):
    tag_objects = []

    root = ET.fromstring(text)
    for child in root:
        tag = Tag(child.attrib["id"])
        for subchild in child:
            tag.add_value(subchild.attrib["value"])
        tag_objects.append(tag)

    return tag_objects

