  name = "${var.cluster_name}-apiserver"
  ip_address = "${google_compute_global_address.apiserver-ipv4.address}"
  ip_protocol = "TCP"
  port_range = "443"
  target = "${google_compute_target_tcp_proxy.apiserver.self_link}"
}

